new_string:
TX_IDLE: begin
                    bit_cnt <= 4'b0;
                    if (enable && !fifo_empty) begin
                        // Frame start: latch LCR, pop FIFO, load tx_buffer
                        lcr_latch  <= LCR;
                        tx_fifo_pop <= 1'b1;
                        // Use LCR directly (not lcr_latch) since lcr_latch hasn't been updated yet
                        case (LCR[1:0])
                            2'b00: tx_buffer <= fifo_rd_data & 8'h1F; // 5-bit
                            2'b01: tx_buffer <= fifo_rd_data & 8'h3F; // 6-bit
                            2'b10: tx_buffer <= fifo_rd_data & 8'h7F; // 7-bit
                            2'b11: tx_buffer <= fifo_rd_data & 8'hFF; // 8-bit
                            default: tx_buffer <= fifo_rd_data & 8'hFF;
                        endcase
                        // Pre-compute parity bit using LCR directly
                        case (LCR[5:4])
                            2'b00: parity_bit <= ^(fifo_rd_data & ((LCR[1:0] == 2'b00) ? 8'h1F : (LCR[1:0] == 2'b01) ? 8'h3F : (LCR[1:0] == 2'b10) ? 8'h7F : 8'hFF)); // Even parity
                            2'b01: parity_bit <= ~^(fifo_rd_data & ((LCR[1:0] == 2'b00) ? 8'h1F : (LCR[1:0] == 2'b01) ? 8'h3F : (LCR[1:0] == 2'b10) ? 8'h7F : 8'hFF)); // Odd parity
                            2'b10: parity_bit <= 1'b1; // Stick parity 1
                            2'b11: parity_bit <= 1'b0; // Stick parity 0
                            default: parity_bit <= 1'b0;
                        endcase
                    end
                end

old_string:
TX_IDLE: begin
                    bit_cnt <= 4'b0;
                    if (enable && !fifo_empty) begin
                        // Frame start: latch LCR, pop FIFO, load tx_buffer
                        lcr_latch  <= LCR;
                        tx_fifo_pop <= 1'b1;
                        tx_buffer  <= fifo_rd_data & data_mask; // LSB-aligned, upper bits zeroed
                        // Pre-compute parity bit
                        case (parity_type)
                            2'b00: parity_bit <= ^(fifo_rd_data & data_mask); // Even parity
                            2'b01: parity_bit <= ~^(fifo_rd_data & data_mask); // Odd parity
                            2'b10: parity_bit <= 1'b1; // Stick parity 1
                            2'b11: parity_bit <= 1'b0; // Stick parity 0
                            default: parity_bit <= 1'b0;
                        endcase
                        // Note: parity_en comes from LCR[3] which is being latched this cycle
                        // We use LCR directly here since lcr_latch hasn't been updated yet
                        // The parity_bit computation uses LCR[5:4] for type
                        // But parity_en (LCR[3]) determines whether we enter TX_PARITY state
                        // This is handled in next_state logic using lcr_latch after it's latched
                    end
                end
